        std::env::remove_var("NEX_TEST_ETC_ROOT");
        std::env::remove_var("NEX_TESTING");

        assert!(report
            .findings
            .iter()
            .any(|f| f.id == "darwin.synthetic-conf.mode"));
    }
}
