fn reset_existing(existing: &ExistingHomebrew) -> Result<()> {
    let prefix = existing.prefix.to_string_lossy().to_string();
    if prefix != "/usr/local" && prefix != "/opt/homebrew" {
        bail!("refusing to reset unexpected Homebrew prefix {prefix}");
    }

    let paths = [
        existing.prefix.join("Homebrew"),
        existing.prefix.join("bin/brew"),
        existing.prefix.join("share/doc/homebrew"),
        existing.prefix.join("share/man/man1/brew.1"),
        existing.prefix.join("share/zsh/site-functions/_brew"),
        existing.prefix.join("etc/bash_completion.d/brew"),
    ];

    for path in paths.iter().filter(|path| path.exists()) {
        let status = Command::new("sudo")
            .arg("rm")
            .arg("-rf")
            .arg(path)
            .status()
            .with_context(|| format!("failed to remove {}", path.display()))?;
        if !status.success() {
            bail!("failed to remove {}", path.display());
        }
    }
    eprintln!(
        "  {} reset unmanaged Homebrew at {}",
        style("✓").green(),
        existing.prefix.display()
    );
    Ok(())
}

