    std::process::Command::new("git")
        .args(["config", "--global", key])
        .output()
        .ok()
        .filter(|output| output.status.success())
        .map(|output| crate::exec::captured_text(&output.stdout).trim().to_string())
        .filter(|value| !value.is_empty())
}

